// WorkshopServiceServer is the server API for WorkshopService service.
// All implementations must embed UnimplementedWorkshopServiceServer
// for forward compatibility.
type WorkshopServiceServer interface {
	// --- Workshop CRUD ---
	CreateWorkshop(context.Context, *CreateWorkshopRequest) (*CreateWorkshopResponse, error)
	GetWorkshop(context.Context, *GetWorkshopRequest) (*GetWorkshopResponse, error)
	UpdateWorkshop(context.Context, *UpdateWorkshopRequest) (*UpdateWorkshopResponse, error)
	ListWorkshops(context.Context, *ListWorkshopsRequest) (*ListWorkshopsResponse, error)
	ListWorkshopOrgIDs(context.Context, *ListWorkshopOrgIDsRequest) (*ListWorkshopOrgIDsResponse, error)
	// GetWorkshopByLegacyName resolves a legacy workshop name (carried by
	// new_order's webhook payload, e.g. "Autobody Almaty") to a workshop id.
	// Returns NOT_FOUND when the name is not mapped.
	GetWorkshopByLegacyName(context.Context, *GetWorkshopByLegacyNameRequest) (*GetWorkshopByLegacyNameResponse, error)
	// --- Repair Order ---
	CreateRepairOrder(context.Context, *CreateRepairOrderRequest) (*CreateRepairOrderResponse, error)
	GetRepairOrder(context.Context, *GetRepairOrderRequest) (*GetRepairOrderResponse, error)
	UpdateRepairOrder(context.Context, *UpdateRepairOrderRequest) (*UpdateRepairOrderResponse, error)
	UpdateRepairOrderStatus(context.Context, *UpdateRepairOrderStatusRequest) (*UpdateRepairOrderStatusResponse, error)
	ListRepairOrders(context.Context, *ListRepairOrdersRequest) (*ListRepairOrdersResponse, error)
	GetKanban(context.Context, *GetKanbanRequest) (*GetKanbanResponse, error)
	// --- Car Work ---
	CreateCarWork(context.Context, *CreateCarWorkRequest) (*CreateCarWorkResponse, error)
	UpdateCarWork(context.Context, *UpdateCarWorkRequest) (*UpdateCarWorkResponse, error)
	DeleteCarWork(context.Context, *DeleteCarWorkRequest) (*DeleteCarWorkResponse, error)
	ListCarWorks(context.Context, *ListCarWorksRequest) (*ListCarWorksResponse, error)
	MarkCarWorkDone(context.Context, *MarkCarWorkDoneRequest) (*MarkCarWorkDoneResponse, error)
	ClockIn(context.Context, *ClockInRequest) (*ClockInResponse, error)
	ClockOut(context.Context, *ClockOutRequest) (*ClockOutResponse, error)
	// --- Master ---
	CreateMaster(context.Context, *CreateMasterRequest) (*CreateMasterResponse, error)
	GetMaster(context.Context, *GetMasterRequest) (*GetMasterResponse, error)
	UpdateMaster(context.Context, *UpdateMasterRequest) (*UpdateMasterResponse, error)
	FireMaster(context.Context, *FireMasterRequest) (*FireMasterResponse, error)
	ListMasters(context.Context, *ListMastersRequest) (*ListMastersResponse, error)
	// --- Master Rates ---
	SetMasterHourRate(context.Context, *SetMasterHourRateRequest) (*SetMasterHourRateResponse, error)
	SetMasterFixSalary(context.Context, *SetMasterFixSalaryRequest) (*SetMasterFixSalaryResponse, error)
	GetMasterRateHistory(context.Context, *GetMasterRateHistoryRequest) (*GetMasterRateHistoryResponse, error)
	// --- Salary ---
	CalculateSalary(context.Context, *CalculateSalaryRequest) (*CalculateSalaryResponse, error)
	GetSalaryBreakdown(context.Context, *GetSalaryBreakdownRequest) (*GetSalaryBreakdownResponse, error)
	CreateBonus(context.Context, *CreateBonusRequest) (*CreateBonusResponse, error)
	CreateFine(context.Context, *CreateFineRequest) (*CreateFineResponse, error)
	CreateAdvance(context.Context, *CreateAdvanceRequest) (*CreateAdvanceResponse, error)
	DeleteBonus(context.Context, *DeleteBonusRequest) (*DeleteBonusResponse, error)
	DeleteFine(context.Context, *DeleteFineRequest) (*DeleteFineResponse, error)
	// --- Outsource ---
	PublishOutsource(context.Context, *PublishOutsourceRequest) (*PublishOutsourceResponse, error)
	AcceptOutsource(context.Context, *AcceptOutsourceRequest) (*AcceptOutsourceResponse, error)
	ListOutsourceRequests(context.Context, *ListOutsourceRequestsRequest) (*ListOutsourceRequestsResponse, error)
	GetOutsourceKanban(context.Context, *GetOutsourceKanbanRequest) (*GetOutsourceKanbanResponse, error)
	UpdateOutsourceStatus(context.Context, *UpdateOutsourceStatusRequest) (*UpdateOutsourceStatusResponse, error)
	// --- Analytics ---
	GetWorkshopStats(context.Context, *GetWorkshopStatsRequest) (*GetWorkshopStatsResponse, error)
	GetMasterPerformance(context.Context, *GetMasterPerformanceRequest) (*GetMasterPerformanceResponse, error)
	GetDailyReport(context.Context, *GetDailyReportRequest) (*GetDailyReportResponse, error)
	// --- Comments ---
	AddComment(context.Context, *AddCommentRequest) (*AddCommentResponse, error)
	ListComments(context.Context, *ListCommentsRequest) (*ListCommentsResponse, error)
	// --- Photos ---
	UploadPhoto(context.Context, *UploadPhotoRequest) (*UploadPhotoResponse, error)
	ListPhotos(context.Context, *ListPhotosRequest) (*ListPhotosResponse, error)
	DeletePhoto(context.Context, *DeletePhotoRequest) (*DeletePhotoResponse, error)
	// --- QC Checklist ---
	GetQCChecklist(context.Context, *GetQCChecklistRequest) (*GetQCChecklistResponse, error)
	SubmitQCChecklist(context.Context, *SubmitQCChecklistRequest) (*SubmitQCChecklistResponse, error)
	RejectQCItem(context.Context, *RejectQCItemRequest) (*RejectQCItemResponse, error)
	// --- Status History ---
	ListStatusHistory(context.Context, *ListStatusHistoryRequest) (*ListStatusHistoryResponse, error)
	// --- Materials ---
	CreateMaterial(context.Context, *CreateMaterialRequest) (*CreateMaterialResponse, error)
	UpdateMaterial(context.Context, *UpdateMaterialRequest) (*UpdateMaterialResponse, error)
	ListMaterials(context.Context, *ListMaterialsRequest) (*ListMaterialsResponse, error)
	AddMaterialStock(context.Context, *AddMaterialStockRequest) (*AddMaterialStockResponse, error)
	WriteOffMaterial(context.Context, *WriteOffMaterialRequest) (*WriteOffMaterialResponse, error)
	GetMaterialStock(context.Context, *GetMaterialStockRequest) (*GetMaterialStockResponse, error)
	ListMaterialTransactions(context.Context, *ListMaterialTransactionsRequest) (*ListMaterialTransactionsResponse, error)
	GetMasterMaterialExpenses(context.Context, *GetMasterMaterialExpensesRequest) (*GetMasterMaterialExpensesResponse, error)
	// --- Client API (for mobile app) ---
	GetClientOrderStatus(context.Context, *GetClientOrderStatusRequest) (*GetClientOrderStatusResponse, error)
	GetClientOrderPhotos(context.Context, *GetClientOrderPhotosRequest) (*GetClientOrderPhotosResponse, error)
	GetClientOrderTimeline(context.Context, *GetClientOrderTimelineRequest) (*GetClientOrderTimelineResponse, error)
	GetClientEstimate(context.Context, *GetClientEstimateRequest) (*GetClientEstimateResponse, error)
	SendForApproval(context.Context, *SendForApprovalRequest) (*SendForApprovalResponse, error)
	ApproveEstimate(context.Context, *ApproveEstimateRequest) (*ApproveEstimateResponse, error)
	RejectEstimate(context.Context, *RejectEstimateRequest) (*RejectEstimateResponse, error)
	// --- CRM Integration ---
	CreateOrderFromCRM(context.Context, *CreateOrderFromCRMRequest) (*CreateOrderFromCRMResponse, error)
	SyncCRMDeals(context.Context, *SyncCRMDealsRequest) (*SyncCRMDealsResponse, error)
	GetCRMSyncStatus(context.Context, *GetCRMSyncStatusRequest) (*GetCRMSyncStatusResponse, error)
	// --- Master Telegram ---
	SetMasterTelegram(context.Context, *SetMasterTelegramRequest) (*SetMasterTelegramResponse, error)
	GetMasterByTelegram(context.Context, *GetMasterByTelegramRequest) (*GetMasterByTelegramResponse, error)
	// --- Pricing ---
	SetDiscount(context.Context, *SetDiscountRequest) (*SetDiscountResponse, error)
	SetMarkup(context.Context, *SetMarkupRequest) (*SetMarkupResponse, error)
	SetWorkshopMarkup(context.Context, *SetWorkshopMarkupRequest) (*SetWorkshopMarkupResponse, error)
	GetPricingBreakdown(context.Context, *GetPricingBreakdownRequest) (*GetPricingBreakdownResponse, error)
	// --- Payments ---
	MarkPaidManual(context.Context, *MarkPaidManualRequest) (*MarkPaidManualResponse, error)
	CancelPayment(context.Context, *CancelPaymentRequest) (*CancelPaymentResponse, error)
	GetPaymentHistory(context.Context, *GetPaymentHistoryRequest) (*GetPaymentHistoryResponse, error)
	// --- Warranty ---
	GetWarrantyOrders(context.Context, *GetWarrantyOrdersRequest) (*GetWarrantyOrdersResponse, error)
	// --- Client completion confirmation ---
	// Called by the mobile client after the workshop marks the order as DELIVERED.
	// Transitions the order to CLOSED_BY_CLIENT and optionally creates a review.
	ConfirmOrderCompletionByClient(context.Context, *ConfirmOrderCompletionByClientRequest) (*ConfirmOrderCompletionByClientResponse, error)
	mustEmbedUnimplementedWorkshopServiceServer()
}

